fn solve(n: i64, m: i64, k: i64) -> i64 {
    if k == 0 {
        return 0;
    }
    if k >= ((n - 1) / 2).ceil() || k >= ((m - 1) / 2).ceil() {
        return (n * m).ceil();
    }
    let rows = (n + 1) / 2;
    let cols = (m + 1) / 2;
    rows * cols
}
